import ast


def decode_cipher(ciphertext):
    # Convert the string representation into a Python object
    data = ast.literal_eval(ciphertext)

    result = []
    for item in data:
        # First element
        if isinstance(item[0], str) and item[0].startswith("0x"):
            result.append(chr(int(item[0], 16)))
        # Last element
        if isinstance(item[-1], str) and item[-1].startswith("0x"):
            result.append(chr(int(item[-1], 16)))
    return "".join(result)


